import{_ as e,o,c as t,a2 as s}from"./chunks/framework.CH-YxFqP.js";const m=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"operations/faq.md","filePath":"operations/faq.md","lastUpdated":1781350447000}'),i={name:"operations/faq.md"};function l(r,a,n,h,d,c){return o(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="为什么默认-compose-文件使用-host-网络" tabindex="-1">为什么默认 Compose 文件使用 host 网络？ <a class="header-anchor" href="#为什么默认-compose-文件使用-host-网络" aria-label="Permalink to &quot;为什么默认 Compose 文件使用 host 网络？&quot;">​</a></h2><p>内嵌 local agent 可以动态创建代理监听端口。host 网络允许这些监听器直接绑定到宿主机，而不需要修改容器端口映射。</p><h2 id="面板数据存储在哪里" tabindex="-1">面板数据存储在哪里？ <a class="header-anchor" href="#面板数据存储在哪里" aria-label="Permalink to &quot;面板数据存储在哪里？&quot;">​</a></h2><p>默认 Docker Compose 部署中，面板数据存储在宿主机 <code>./data</code>，并挂载到容器内。</p><h2 id="根目录-docs-还能继续放临时文档吗" tabindex="-1">根目录 docs 还能继续放临时文档吗？ <a class="header-anchor" href="#根目录-docs-还能继续放临时文档吗" aria-label="Permalink to &quot;根目录 docs 还能继续放临时文档吗？&quot;">​</a></h2><p>可以。公开文档站源码位于 <code>docs-site/</code>，不会占用根目录 <code>docs/</code>。</p><h2 id="为什么我看-emby-还是要挂代理" tabindex="-1">为什么我看 Emby 还是要挂代理？ <a class="header-anchor" href="#为什么我看-emby-还是要挂代理" aria-label="Permalink to &quot;为什么我看 Emby 还是要挂代理？&quot;">​</a></h2><p>先确认播放器里填的是你自己的加速入口域名，而不是公费服/公益服给你的源站域名。Nginx-Reverse-Emby 的作用是让你的 VPS 去访问源站，客户端访问你的 VPS。</p><p>还要确认这台 VPS 自己能访问源站：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://origin.emby.example.net</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果 VPS 到源站也不通，HTTP 规则保存成功也无法解决播放问题。</p><h2 id="http-规则和-l4-规则怎么选" tabindex="-1">HTTP 规则和 L4 规则怎么选？ <a class="header-anchor" href="#http-规则和-l4-规则怎么选" aria-label="Permalink to &quot;HTTP 规则和 L4 规则怎么选？&quot;">​</a></h2><p>反代 Emby/Jellyfin Web 入口，优先用 HTTP 规则。HTTP 规则知道前端 URL、后端 URL、重定向和代理头，适合浏览器、电视盒子和 Emby 客户端。</p><p>只需要转发 TCP/UDP 端口，或者要把 L4 流量接入 Relay 链路时，再使用 L4 规则。</p><h2 id="面板显示-local-是什么" tabindex="-1">面板显示 local 是什么？ <a class="header-anchor" href="#面板显示-local-是什么" aria-label="Permalink to &quot;面板显示 local 是什么？&quot;">​</a></h2><p><code>local</code> 是 Docker Compose 默认启用的内嵌 local agent。它和控制面跑在同一个容器里，但监听端口会绑定到宿主机网络上。</p><h2 id="何时需要关闭-302-307-代理" tabindex="-1">何时需要关闭 302/307 代理？ <a class="header-anchor" href="#何时需要关闭-302-307-代理" aria-label="Permalink to &quot;何时需要关闭 302/307 代理？&quot;">​</a></h2><p>以下场景可以在 HTTP 规则中关闭“代理 302/307 重定向”：</p><ul><li>CDN 回源需要保留原始重定向地址。</li><li>多跳转链接需要客户端直接访问。</li><li>OAuth 回调需要保持重定向地址原样传递。</li></ul>',20)])])}const b=e(i,[["render",l]]);export{m as __pageData,b as default};
